import json, csv, pandas as pd

FIELD_MAP = {
    'user_id':'user_id','id':'user_id','userId':'user_id',
    'email':'email','email_address':'email',
    'full_name':'name','name':'name','userName':'name',
    'registration_date':'created_date','created_at':'created_date','joined':'created_date',
    'status':'status','is_active':'status','active':'status',
}

def norm_status(v):
    if isinstance(v,bool): return 'active' if v else 'inactive'
    if isinstance(v,str):
        s=v.strip().lower()
        if s in ('true','active'): return 'active'
        if s in ('false','inactive'): return 'inactive'
        return v
    return v

def remap(rec):
    out={}
    for k,v in rec.items():
        if k not in FIELD_MAP: continue
        uk=FIELD_MAP[k]
        if uk=='user_id': v=int(v)
        elif uk=='status': v=norm_status(v)
        else: v=None if v is None else str(v)
        out[uk]=v
    return out

# source_a
with open('/data/source_a/users.json') as f:
    a=[remap(r) for r in json.load(f)]
# source_b
b=[]
with open('/data/source_b/users.csv') as f:
    for r in csv.DictReader(f):
        b.append(remap(r))
# source_c
c=[remap(r) for r in pd.read_parquet('/data/source_c/users.parquet').to_dict('records')]

sources={'source_a':{r['user_id']:r for r in a},
         'source_b':{r['user_id']:r for r in b},
         'source_c':{r['user_id']:r for r in c}}
priority=['source_a','source_b','source_c']

uids=sorted(set().union(*[set(s) for s in sources.values()]))
CONFLICT_FIELDS=['name','email','created_date','status']

merged=[]
conflicts=[]
for uid in uids:
    present=[(s,sources[s][uid]) for s in priority if uid in sources[s]]
    row={'user_id':uid}
    # merge fields by priority
    for uk in ['name','email','created_date','status']:
        for s,rec in present:
            if uk in rec and rec[uk] is not None:
                row[uk]=rec[uk]; break
    merged.append(row)
    # conflicts
    for uk in CONFLICT_FIELDS:
        vals={s:rec[uk] for s,rec in present if uk in rec and rec[uk] is not None}
        if len(set(vals.values()))>1:
            selected=None
            for s in priority:
                if s in vals: selected=vals[s]; break
            conflicts.append({'user_id':uid,'field':uk,
                'values':{s:vals[s] for s in priority if s in vals},
                'selected':selected})

df=pd.DataFrame(merged)
for col in ['name','email','created_date','status']:
    if col not in df: df[col]=None
df=df[['user_id','name','email','created_date','status']]
df['user_id']=df['user_id'].astype('int64')
for col in ['name','email','created_date','status']:
    df[col]=df[col].astype('string')
df.to_parquet('/app/merged_users.parquet',index=False)

report={'total_conflicts':len(conflicts),'conflicts':conflicts}
with open('/app/conflicts.json','w') as f:
    json.dump(report,f,indent=2)

print(df.to_string())
print('conflicts',len(conflicts))
for c_ in conflicts: print(c_['user_id'],c_['field'],'->',c_['selected'])
EOF
